import React, { useState, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { base44 } from '@/api/base44Client';
import { useAuth } from '@/lib/AuthContext';
import { format, startOfWeek, endOfWeek, startOfMonth, endOfMonth } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { DollarSign, Clock, TrendingUp, Download, Settings, FileText } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import PageHeader from '@/components/shared/PageHeader';
import StatCard from '@/components/shared/StatCard';
import ProfessionalSettingsDialog from '@/components/settings/ProfessionalSettingsDialog';
import { formatCurrency, formatDuration, ROOM_LABELS, STATUS_LABELS, STATUS_COLORS } from '@/lib/utils/time';
import { toDateSafe } from '@/lib/utils/date';
import { buildUserAppointments } from '@/lib/utils/appointments';

// Bibliotecas para o PDF
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable'; 

export default function Financial() {
  const { user } = useAuth();
  const [periodFilter, setPeriodFilter] = useState('month');
  const [patientFilter, setPatientFilter] = useState('all');
  
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const { data: appointments = [] } = useQuery({
    queryKey: ['appointments', user?.uid],
    queryFn: () => base44.entities.Appointment.filter(),
    enabled: !!user?.uid,
  });

  const { data: patients = [] } = useQuery({
    queryKey: ['patients', user?.uid],
    queryFn: () => base44.entities.Patient.list(),
    enabled: !!user?.uid,
  });

  const { data: allBookings = [] } = useQuery({
    queryKey: ['all-appointments'],
    queryFn: () => base44.entities.Appointment.list(),
    enabled: !!user?.uid,
  });

  const patientRateById = useMemo(
    () => new Map(patients.map((p) => [p.id, Number(p.hourly_rate || 0)])),
    [patients]
  );

  const financeAppointments = useMemo(() => {
    return buildUserAppointments(appointments, allBookings, user, patientRateById);
  }, [appointments, allBookings, user?.uid, user?.email, patientRateById]);

  const filtered = useMemo(() => {
    const now = new Date();
    let start, end;
    
    if (periodFilter === 'week') {
      start = startOfWeek(now, { weekStartsOn: 1 });
      end = endOfWeek(now, { weekStartsOn: 1 });
    } else if (periodFilter === 'month') {
      start = startOfMonth(now);
      end = endOfMonth(now);
    } else if (periodFilter === 'custom') {
      start = customStart ? new Date(customStart + 'T00:00:00') : new Date(0);
      end = customEnd ? new Date(customEnd + 'T23:59:59') : new Date(8640000000000000); 
    }

    return financeAppointments.filter((a) => {
      const d = toDateSafe(a.date);
      const inRange = !!d && d >= start && d <= end;
      const matchPatient = patientFilter === 'all' || a.patient_id === patientFilter;
      return inRange && matchPatient;
    });
  }, [financeAppointments, periodFilter, patientFilter, customStart, customEnd]);

  const realized = filtered.filter((a) => a.status === 'realizado');
  const totalValue = realized.reduce((sum, a) => sum + (a.total_value || 0), 0);
  const totalMinutes = realized.reduce((sum, a) => sum + (a.duration_minutes || 0), 0);
  const avgPerSession = realized.length > 0 ? totalValue / realized.length : 0;

  const exportPDF = () => {
    const doc = new jsPDF('p', 'mm', 'a4');
    
    const professionalInfo = JSON.parse(localStorage.getItem('lumie_professional_info') || '{}');
    const userLogo = professionalInfo.logoBase64;
    
    // Atenção: O SEU CÓDIGO BASE64 GIGANTE DO TIMBRADO DEVE FICAR AQUI
    const LUMIE_LETTERHEAD_BASE64 = 'data:image/jpeg;base64,'; 

    // --- Cores Lumie baseadas no PDF de referência ---
    const LUMIE_CYAN_RGB = [222, 184, 135]; 

    // Dimensões da página
    const pageSize = doc.internal.pageSize;
    const pageWidth = pageSize.getWidth();
    const pageHeight = pageSize.getHeight();
    const marginX = 15;

    // Função que desenha o fundo e cabeçalho fixo (sempre no topo)
    const addBackgroundAndHeader = () => {
      // 1. Fundo Timbrado da Lumie
      if (LUMIE_LETTERHEAD_BASE64 && LUMIE_LETTERHEAD_BASE64.startsWith('data:image')) {
        doc.addImage(LUMIE_LETTERHEAD_BASE64, 'PNG', 0, 0, pageWidth, pageHeight, undefined, 'FAST');
      }

      // 2. Logo do Profissional (canto superior esquerdo)
      if (userLogo) {
        doc.addImage(userLogo, 'PNG', marginX, 12, 30, 20);
      }

      // 3. Texto do Profissional (Alinhado à direita)
      let yPosText = 18;
      doc.setFontSize(10);
      doc.setFont("helvetica", "bold");
      doc.text(professionalInfo.fullName || 'PROFISSIONAL LUMIE', pageWidth - marginX, yPosText, { align: 'right' });
      yPosText += 5;
      
      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      if (professionalInfo.specialty) {
        doc.text(`Especialidade: ${professionalInfo.specialty}`, pageWidth - marginX, yPosText, { align: 'right' });
        yPosText += 5;
      }
      if (professionalInfo.registry) {
        doc.text(`Registro: ${professionalInfo.registry}`, pageWidth - marginX, yPosText, { align: 'right' });
        yPosText += 5;
      }
    };

    // --- Preparação dos dados da tabela para cálculo ---
    const tableData = filtered
      .sort((a, b) => String(a.date).localeCompare(String(b.date)))
      .map(a => [
        format(toDateSafe(a.date), "dd/MM/yyyy"),
        a.patient_name,
        `${a.start_time} às ${a.end_time}`,
        formatCurrency(a.total_value || 0)
      ]);

    // --- CÁLCULO DE CENTRALIZAÇÃO VERTICAL ---
    // Precisamos estimar a altura total do bloco de conteúdo
    const headerTextsHeight = 20; // Título + Dados Paciente/Período
    const footerTextsHeight = 20; // Apenas o total (assinatura removida)
    const separatorHeight = 5;

    // autoTable: estimativa de altura da tabela (cabeçalho + linhas)
    const rowHeightEst = 7;
    const headHeightEst = 9;
    const estimatedTableHeight = headHeightEst + (tableData.length * rowHeightEst);

    const totalContentHeight = headerTextsHeight + separatorHeight + estimatedTableHeight + footerTextsHeight;

    // Definimos o ponto de partida vertical para centralizar
    let yTrack = (pageHeight - totalContentHeight) / 2;

    // Segurança: Não deixa começar acima de 50mm para não chocar com o cabeçalho do timbrado
    if (yTrack < 50) yTrack = 50; 

    // Intercetamos a criação de novas páginas para desenhar o fundo
    const originalAddPage = doc.addPage.bind(doc);
    doc.addPage = function() {
      originalAddPage();
      addBackgroundAndHeader();
      return this;
    };

    // 1. Pinta o fundo na PRIMEIRA PÁGINA
    addBackgroundAndHeader();

    // --- Desenho do Conteúdo Centralizado ---

    // Título - Centralizado horizontalmente
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text('EXTRATO DE ATENDIMENTOS', pageWidth / 2, yTrack, { align: 'center' });
    yTrack += 10;

    // Dados do Relatório (Alinhados à esquerda)
    doc.setFontSize(10);
    doc.text(`Paciente:`, marginX, yTrack);
    doc.setFont("helvetica", "normal");
    const patientName = patientFilter === 'all' ? 'Todos os Pacientes' : patients.find(p => p.id === patientFilter)?.name;
    doc.text(`${patientName}`, 33, yTrack);
    yTrack += 5;
    
    doc.setFont("helvetica", "bold");
    doc.text(`Período:`, marginX, yTrack);
    doc.setFont("helvetica", "normal");
    let periodText = 'Período completo';
    if (periodFilter === 'custom' && customStart && customEnd) {
      periodText = `De ${format(new Date(customStart + 'T00:00:00'), 'dd/MM/yyyy')} a ${format(new Date(customEnd + 'T00:00:00'), 'dd/MM/yyyy')}`;
    } else if (periodFilter === 'month') {
      periodText = `Mês atual`;
    } else if (periodFilter === 'week') {
      periodText = `Semana atual`;
    }
    doc.text(`${periodText}`, 33, yTrack);
    yTrack += 3;

    doc.setLineWidth(0.2);
    doc.line(marginX, yTrack, pageWidth - marginX, yTrack);
    yTrack += 3; // Margem antes da tabela

    // 5. Tabela de Sessões com COR ATUALIZADA (Ciano Lumie)
    autoTable(doc, {
      startY: yTrack,
      head: [['Data', 'Paciente', 'Horário', 'Valor (R$)']],
      body: tableData,
      theme: 'striped',
      // ATUALIZAÇÃO DE COR: Usando o tom de Ciano mais claro padronizado com o print
      headStyles: { fillColor: LUMIE_CYAN_RGB }, 
      margin: { left: marginX, right: marginX },
    });

    yTrack = doc.lastAutoTable.finalY + 15;
    
    // Verificação de quebra de página para o rodapé
    if (yTrack > pageHeight - 60) {
      doc.addPage();
      yTrack = 60; 
    }

    // 6. Rodapé (assinatura removida)
    doc.setFont("helvetica", "bold");
    doc.setFontSize(11);
    doc.text(`Total a Pagar (Apenas Atendimentos Realizados): ${formatCurrency(totalValue)}`, marginX, yTrack);

    const fileName = `extrato_${patientName.replace(/\s+/g, '_')}_${format(new Date(), 'dd-MM-yyyy')}.pdf`;
    doc.save(fileName);
  };

  const exportCSV = () => {
    const headers = ['Data', 'Paciente', 'Sala', 'Início', 'Término', 'Duração', 'Valor', 'Status'];
    const rows = filtered.map((a) => [
      a.date, a.patient_name, ROOM_LABELS[a.room], a.start_time, a.end_time,
      formatDuration(a.duration_minutes || 0), (a.total_value || 0).toFixed(2), STATUS_LABELS[a.status],
    ]);

    const csv = [headers.join(','), ...rows.map((r) => r.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `relatorio-${format(new Date(), 'yyyy-MM-dd')}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div>
      <PageHeader
        title="Financeiro"
        subtitle="Resumo financeiro e relatórios"
        actions={
          <div className="flex gap-2">
            <Button variant="outline" onClick={() => setIsSettingsOpen(true)}>
              <Settings className="w-4 h-4 mr-2" /> Configurações do Recibo
            </Button>
            <Button variant="outline" onClick={exportCSV} title="Exportar para Excel">
              <Download className="w-4 h-4" />
            </Button>
            <Button onClick={exportPDF} className="bg-primary text-primary-foreground">
              <FileText className="w-4 h-4 mr-2" /> Gerar PDF (Recibo)
            </Button>
          </div>
        }
      />

      <div className="flex flex-wrap gap-3 mb-6 items-end bg-card p-4 rounded-lg border border-border">
        <div>
          <Label className="text-xs mb-1 block">Período</Label>
          <Select value={periodFilter} onValueChange={setPeriodFilter}>
            <SelectTrigger className="w-40"><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="week">Esta semana</SelectItem>
              <SelectItem value="month">Este mês</SelectItem>
              <SelectItem value="custom">Personalizado...</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {periodFilter === 'custom' && (
          <div className="flex gap-2 items-end bg-secondary/20 p-2 rounded-md border border-border">
            <div>
              <Label className="text-xs mb-1 block">Data Inicial</Label>
              <Input 
                type="date" 
                value={customStart} 
                onChange={(e) => setCustomStart(e.target.value)}
                className="w-auto h-9"
              />
            </div>
            <div>
              <Label className="text-xs mb-1 block">Data Final</Label>
              <Input 
                type="date" 
                value={customEnd} 
                onChange={(e) => setCustomEnd(e.target.value)}
                className="w-auto h-9"
              />
            </div>
          </div>
        )}

        <div>
          <Label className="text-xs mb-1 block">Paciente</Label>
          <Select value={patientFilter} onValueChange={setPatientFilter}>
            <SelectTrigger className="w-56"><SelectValue placeholder="Todos os pacientes" /></SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os pacientes</SelectItem>
              {patients.map((p) => (
                <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
        <StatCard title="Total Faturado (Realizados)" value={formatCurrency(totalValue)} icon={DollarSign} />
        <StatCard title="Horas Atendidas" value={formatDuration(totalMinutes)} icon={Clock} />
        <StatCard title="Média por Sessão" value={formatCurrency(avgPerSession)} icon={TrendingUp} />
      </div>

      <Card className="border border-border overflow-hidden">
        <div className="overflow-x-auto">
          <Table>
            <TableHeader>
              <TableRow className="bg-muted/50">
                <TableHead>Data</TableHead>
                <TableHead>Paciente</TableHead>
                <TableHead className="hidden sm:table-cell">Sala</TableHead>
                <TableHead>Horário</TableHead>
                <TableHead className="hidden sm:table-cell">Duração</TableHead>
                <TableHead>Valor</TableHead>
                <TableHead>Status</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filtered.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={7} className="text-center text-muted-foreground py-8">
                    Nenhum atendimento encontrado no período selecionado.
                  </TableCell>
                </TableRow>
              ) : (
                filtered
                  .sort((a, b) => String(b.date).localeCompare(String(a.date)) || b.start_time.localeCompare(a.start_time))
                  .map((apt) => (
                    <TableRow key={apt.id}>
                      <TableCell className="text-sm">{format(toDateSafe(apt.date) || new Date(), "dd/MM/yy")}</TableCell>
                      <TableCell className="font-medium text-sm">{apt.patient_name}</TableCell>
                      <TableCell className="text-sm hidden sm:table-cell">{ROOM_LABELS[apt.room]}</TableCell>
                      <TableCell className="text-sm">{apt.start_time} – {apt.end_time}</TableCell>
                      <TableCell className="text-sm hidden sm:table-cell">{formatDuration(apt.duration_minutes || 0)}</TableCell>
                      <TableCell className="font-medium text-sm">{formatCurrency(apt.total_value || 0)}</TableCell>
                      <TableCell>
                        <Badge variant="secondary" className={`text-xs ${STATUS_COLORS[apt.status]}`}>
                          {STATUS_LABELS[apt.status]}
                        </Badge>
                      </TableCell>
                    </TableRow>
                  ))
              )}
            </TableBody>
          </Table>
        </div>
      </Card>

      <ProfessionalSettingsDialog 
        open={isSettingsOpen} 
        onOpenChange={setIsSettingsOpen} 
      />
    </div>
  );
}